func curlExample(baseURL string) string {
	return `curl ` + baseURL + `/chat/completions \
  -H "Authorization: Bearer <clé-api>" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "<organisation>/<modèle>",
    "messages": [{"role": "user", "content": "Bonjour !"}]
  }'`
}

func pythonExample(baseURL string) string {
	return `from openai import OpenAI

client = OpenAI(
    base_url="` + baseURL + `",
    api_key="<clé-api>",
)

response = client.chat.completions.create(
    model="<organisation>/<modèle>",
    messages=[{"role": "user", "content": "Bonjour !"}],
)
print(response.choices[0].message.content)`
}

func claudeCodeExample(baseURL string) string {
	return `export ANTHROPIC_BASE_URL="` + baseURL + `"
export ANTHROPIC_AUTH_TOKEN="<clé-api>"
export ANTHROPIC_MODEL="<organisation>/<modèle>"
export ANTHROPIC_SMALL_FAST_MODEL="<organisation>/<modèle>"
export CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC=1

claude`
}

func openCodeConfigExample(baseURL string, modelUsages []ModelUsage) string {
	type modelLimit struct {
		Context int64 `json:"context,omitempty"`
		Output  int64 `json:"output,omitempty"`
	}
	type modelEntry struct {
		Name  string      `json:"name"`
		Limit *modelLimit `json:"limit,omitempty"`
	}
	type providerOptions struct {
		BaseURL string `json:"baseURL"`
		APIKey  string `json:"apiKey"`
	}
	type providerEntry struct {
		NPM     string                `json:"npm"`
		Name    string                `json:"name"`
		Options providerOptions       `json:"options"`
		Models  map[string]modelEntry `json:"models"`
	}
	type configRoot struct {
		Schema   string                   `json:"$schema"`
		Provider map[string]providerEntry `json:"provider"`
	}

	models := make(map[string]modelEntry)
	for _, mu := range modelUsages {
		if mu.Model.Capabilities().Embeddings {
			continue
		}
		var name string
		if mu.Org != nil {
			name = mu.Org.Slug() + "/" + mu.Model.ProxyName()
		} else {
			name = mu.Model.ProxyName()
		}

		entry := modelEntry{Name: name}

		if ctx := mu.Model.ContextWindow(); ctx > 0 {
			if entry.Limit == nil {
				entry.Limit = &modelLimit{}
			}
			entry.Limit.Context = ctx
		}
		if out := mu.Model.OutputWindow(); out > 0 {
			if entry.Limit == nil {
				entry.Limit = &modelLimit{}
			}
			entry.Limit.Output = out
		}

		models[name] = entry
	}

	cfg := configRoot{
		Schema: "https://opencode.ai/config.json",
		Provider: map[string]providerEntry{
			"xolo": {
				NPM:  "@ai-sdk/openai-compatible",
				Name: "Xolo",
				Options: providerOptions{
					BaseURL: baseURL,
					APIKey:  "{env:XOLO_API_KEY}",
				},
				Models: models,
			},
		},
	}

	data, err := json.MarshalIndent(cfg, "", "  ")
	if err != nil {
		return ""
	}
	return string(data)
}

func formatCostPerM(microcentsPer1K int64, currency string) string {
	return common.FormatCost(microcentsPer1K*1000, currency)
}

func orgCurrency(org model.Organization) string {
	if org == nil {
		return "USD"
	}
	currency := org.Currency()
	if currency == "" {
		return "USD"
	}
	return currency
}

